(function() {
  function decode(data) {
    if (!data) return null;
    // If it's already decoded text (from a query), return as-is
    if (typeof data === 'string' && data.indexOf(',') > -1 && data.indexOf('\n') > -1) {
      return data;
    }
    try { return atob(data); } catch(e) { return data; }
  }
  function parseCSV(text) {
    if (!text || typeof text !== 'string') return [];
    var lines = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n').filter(function(l) { return l.trim(); });
    if (!lines.length) return [];
    var headers = lines[0].split(',');
    return lines.slice(1).map(function(line) {
      var values = line.split(',');
      return headers.reduce(function(obj, h, i) {
        obj[h.trim()] = values[i] ? values[i].trim() : '';
        return obj;
      }, {});
    });
  }
  function parseJSONL(text) {
    if (!text || typeof text !== 'string') return [];
    var lines = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n').filter(function(l) { return l.trim(); });
    return lines.map(function(line) {
      try { return JSON.parse(line); } catch(e) { return null; }
    }).filter(function(x) { return x !== null; });
  }
  function safeFile(q) {
    if (!q) return null;
    try {
      // FilePicker widget shape
      if (q.data && q.data.fileData) return q.data.fileData;
      // Query shape — q.data is the payload directly
      if (q.data) return q.data;
      // Already a string
      if (typeof q === 'string') return q;
    } catch(e) {}
    return null;
  }
  var identities = parseCSV(decode(safeFile(Identities_100)));
  var events = parseJSONL(decode(safeFile(Events_jsonl)));
  return {
    "identity": identities,
    "events": events,
    "_debug": {
      "identity_count": identities.length,
      "events_count": events.length,
      "identities_source_type": typeof Identities_100,
      "identities_has_data": !!(Identities_100 && Identities_100.data),
      "identities_has_fileData": !!(Identities_100 && Identities_100.data && Identities_100.data.fileData),
      "events_source_type": typeof Events_jsonl,
      "events_has_data": !!(Events_jsonl && Events_jsonl.data),
      "events_has_fileData": !!(Events_jsonl && Events_jsonl.data && Events_jsonl.data.fileData)
    }
  };
})()
}}

