@charset "UTF-8";
body {
  font-family: "Segoe UI", system-ui, sans-serif;
  background: #ffffff;
  color: #1f2328;
  min-height: 100vh;
}

/* ── Header ─────────────────────────────────────────── */
header {
  background: #ffffff;
  border-bottom: 1px solid #d0d7de;
  padding: 14px 28px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  flex-wrap: wrap;
}

header h1 {
  font-size: 1.05rem;
  font-weight: 600;
  color: #1f2328;
  display: flex;
  align-items: center;
  gap: 10px;
}

.hdr-stat .lbl {
  font-size: 0.68rem;
  color: #656d76;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

header h1 .dot {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: #3fb950;
  display: inline-block;
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.35;
  }
}
.hdr-stats {
  display: flex;
  gap: 24px;
  flex-wrap: wrap;
}

.hdr-stat {
  text-align: center;
}

.hdr-stat .val {
  font-size: 1.3rem;
  font-weight: 700;
  color: #1f2328;
}

.hdr-stat .lbl {
  font-size: 0.68rem;
  color: #8b949e;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

/* ── Tabs ────────────────────────────────────────────── */
.tab-bar {
  background: #f6f8fa;
  border-bottom: 1px solid #d0d7de;
  padding: 0 20px;
  display: flex;
  gap: 2px;
  overflow-x: auto;
}

.tab-btn {
  background: none;
  border: none;
  border-bottom: 3px solid transparent;
  color: #656d76;
  cursor: pointer;
  font-size: 0.8rem;
  font-weight: 500;
  padding: 10px 14px;
  white-space: nowrap;
  transition: color 0.15s, border-color 0.15s;
}

.tab-btn:hover {
  color: #1f2328;
}

.tab-btn.active {
  color: #0969da;
  border-bottom-color: #0969da;
}

/* ── Tab panels ──────────────────────────────────────── */
.panel {
  display: none;
  padding: 20px 28px;
}

.panel.active {
  display: block;
}

/* ── Toolbar (events tab) ────────────────────────────── */
.toolbar {
  background: #f6f8fa;
  border-bottom: 1px solid #d0d7de;
  padding: 10px 28px;
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  align-items: center;
}

.toolbar select, .toolbar input {
  background: #fff;
  border: 1px solid #d0d7de;
  border-radius: 6px;
  color: #1f2328;
  padding: 5px 9px;
  font-size: 0.8rem;
  outline: none;
}

.toolbar select:focus, .toolbar input:focus {
  border-color: #0969da;
  box-shadow: 0 0 0 3px rgba(9, 105, 218, 0.1);
}

.toolbar label {
  font-size: 0.79rem;
  color: #656d76;
}

.toolbar .spacer {
  flex: 1;
}

.refresh-badge {
  font-size: 0.73rem;
  color: #656d76;
  display: flex;
  align-items: center;
  gap: 6px;
}

.refresh-badge input[type=checkbox] {
  accent-color: #1a7f37;
}

/* ── Generic panel cards ─────────────────────────────── */
.panel-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(340px, 1fr));
  gap: 18px;
  margin-top: 4px;
}

.card {
  background: #f6f8fa;
  border: 1px solid #d0d7de;
  border-radius: 8px;
  padding: 16px 18px;
}

.card h3 {
  font-size: 0.82rem;
  font-weight: 600;
  color: #656d76;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 12px;
}

.card .big-num {
  font-size: 2.2rem;
  font-weight: 700;
  color: #1f2328;
}

.card .sub {
  font-size: 0.75rem;
  color: #656d76;
  margin-top: 2px;
}

/* ── Tables ──────────────────────────────────────────── */
.tbl-wrap {
  overflow-x: auto;
  margin-top: 8px;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.8rem;
}

thead th {
  text-align: left;
  padding: 7px 10px;
  color: #656d76;
  font-weight: 600;
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  border-bottom: 1px solid #d0d7de;
  white-space: nowrap;
}

tbody tr {
  border-bottom: 1px solid #eaeef2;
}

tbody tr:hover {
  background: #f6f8fa;
}

td {
  padding: 7px 10px;
  vertical-align: middle;
}

/* ── Badges ──────────────────────────────────────────── */
.badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 20px;
  font-size: 0.7rem;
  font-weight: 600;
  white-space: nowrap;
}

.badge-human      {
  background: #dafbe1;
  color: #116329;
}

.badge-automated  {
  background: #ffebe9;
  color: #a40e26;
}

.badge-agent      {
  background: #fff8c5;
  color: #7d4e00;
}

.badge-unknown    {
  background: #f0f0f0;
  color: #656d76;
}

.badge-llm        {
  background: #ddf4ff;
  color: #0550ae;
}

.badge-tool        {
  background: #fbefff;
  color: #622cbc;
}

.badge-error      {
  background: #ffebe9;
  color: #a40e26;
}

.badge-critical    {
  background: #ffebe9;
  color: #a40e26;
}

.badge-warning    {
  background: #fff8c5;
  color: #7d4e00;
}

.badge-investigate {
  background: #fff1e5;
  color: #953800;
}

.badge-monitor    {
  background: #ddf4ff;
  color: #0550ae;
}

.badge-stable      {
  background: #dafbe1;
  color: #116329;
}

.badge-gap        {
  background: #ffebe9;
  color: #a40e26;
}

.badge-ok          {
  background: #dafbe1;
  color: #116329;
}

.alert-pill {
  display: inline-block;
  padding: 1px 7px;
  border-radius: 4px;
  font-size: 0.66rem;
  font-weight: 600;
  margin: 1px 2px;
  background: #fff8c5;
  color: #7d4e00;
  border: 1px solid #e3c000;
}

.alert-pill.critical {
  background: #ffebe9;
  color: #a40e26;
  border-color: #f5a8a8;
}

/* ── Chart containers ────────────────────────────────── */
.chart-row {
  display: flex;
  gap: 18px;
  flex-wrap: wrap;
  margin-top: 16px;
}

.chart-box {
  flex: 1 1 260px;
  background: #f6f8fa;
  border: 1px solid #d0d7de;
  border-radius: 8px;
  padding: 16px;
}

.chart-box h3 {
  font-size: 0.78rem;
  color: #656d76;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: 600;
  margin-bottom: 10px;
}

/* ── Topology graph ──────────────────────────────────── */
#topology-canvas {
  width: 100%;
  height: 380px;
  background: #f6f8fa;
  border: 1px solid #d0d7de;
  border-radius: 8px;
  display: block;
}

.topo-legend {
  font-size: 0.73rem;
  color: #656d76;
  margin-top: 8px;
  display: flex;
  gap: 18px;
  flex-wrap: wrap;
}

.topo-legend span {
  display: flex;
  align-items: center;
  gap: 5px;
}

.topo-legend .dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  display: inline-block;
}

/* ── Drift alert feed ────────────────────────────────── */
.alert-row-critical {
  background: #fff5f5;
}

.alert-row-warning  {
  background: #fffbeb;
}

/* ── IAM mode selector ───────────────────────────────── */
.iam-mode-row {
  display: flex;
  gap: 10px;
  margin-bottom: 16px;
  flex-wrap: wrap;
}

.iam-mode-btn {
  background: #fff;
  border: 1px solid #d0d7de;
  border-radius: 20px;
  color: #656d76;
  cursor: pointer;
  font-size: 0.78rem;
  padding: 5px 14px;
  font-weight: 500;
  transition: all 0.15s;
}

.iam-mode-btn.active {
  background: #0969da;
  color: #fff;
  border-color: #0969da;
}

/* ── Sparkline ───────────────────────────────────────── */
.sparkline {
  display: inline-flex;
  align-items: flex-end;
  gap: 2px;
  height: 22px;
}

.sparkline span {
  display: inline-block;
  width: 4px;
  background: #58a6ff;
  border-radius: 1px;
  min-height: 2px;
}

/* ── Empty / loading ─────────────────────────────────── */
.empty {
  text-align: center;
  padding: 48px 20px;
  color: #656d76;
  font-size: 0.84rem;
}

.loading {
  color: #8b949e;
  font-size: 0.8rem;
  padding: 12px 0;
}

/* ── Events table (tab 0) ────────────────────────────── */
.ev-table-wrap {
  overflow-x: auto;
  padding-top: 4px;
}

.ev-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.8rem;
}

.ev-table thead th {
  text-align: left;
  padding: 7px 10px;
  color: #656d76;
  font-weight: 600;
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  border-bottom: 1px solid #d0d7de;
  white-space: nowrap;
}

.ev-table tbody tr {
  border-bottom: 1px solid #eaeef2;
  cursor: pointer;
}

.ev-table tbody tr:hover {
  background: #f6f8fa;
}

.ev-table td {
  padding: 8px 10px;
  vertical-align: top;
  max-width: 260px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.ev-table td.wrap {
  white-space: normal;
  word-break: break-word;
}

.detail-row td {
  padding: 0;
  background: #f6f8fa;
}

.detail-box {
  padding: 14px 18px;
  border-top: 1px solid #d0d7de;
}

.detail-box pre {
  font-size: 0.75rem;
  color: #1f2328;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
  max-height: 280px;
  overflow-y: auto;
}

.signal-pill {
  display: inline-block;
  padding: 1px 6px;
  border-radius: 4px;
  font-size: 0.63rem;
  background: #f0f0f0;
  color: #656d76;
  border: 1px solid #d0d7de;
  margin: 1px 2px;
}

/* Identity types — distinct from event types and entities */
.badge-llmagent {
  background: #ede9fe;
  color: #5b21b6;
  border: 1px solid #c4b5fd;
}

.badge-application {
  background: #e0e7ff;
  color: #3730a3;
  border: 1px solid #a5b4fc;
}

.badge-automation {
  background: #fef3c7;
  color: #92400e;
  border: 1px solid #fcd34d;
}

.badge-humantype {
  background: #dcfce7;
  color: #166534;
  border: 1px solid #86efac;
}

.badge-unknowntype {
  background: #f1f5f9;
  color: #475569;
  border: 1px solid #cbd5e1;
}

/* Event types — cooler palette so they don't clash with entity column */
.badge-evt-user {
  background: #cffafe;
  color: #155e75;
  border: 1px solid #67e8f9;
}

.badge-evt-llm {
  background: #dbeafe;
  color: #1e40af;
  border: 1px solid #93c5fd;
}

.badge-evt-tool {
  background: #f3e8ff;
  color: #6b21a8;
  border: 1px solid #d8b4fe;
}

.badge-evt-error {
  background: #fee2e2;
  color: #991b1b;
  border: 1px solid #fca5a5;
}

.badge-evt-unknown {
  background: #f1f5f9;
  color: #475569;
  border: 1px solid #cbd5e1;
}

