// ─────────────── State ─────────────────────────────────────
let allEvents = [];
let allIdentities = [];
let expandedId = null;
let currentTab = 0;
let sortCol = null;
let sortAsc = true;
const charts = {};
// Backfill missing context on tool_call/error events from their session peers
function enrichEvents(events) {
  const contextByUser = {};
  events.forEach(e => {
    if (e.entity_type && e.model) {
      if (!contextByUser[e.user_id]) contextByUser[e.user_id] = [];
      contextByUser[e.user_id].push(e);
    }
  });
  Object.values(contextByUser).forEach(arr => arr.sort((a, b) => (a.timestamp_ms || 0) - (b.timestamp_ms || 0)));
  return events.map(e => {
    if (e.entity_type && e.model) return e;
    const peers = contextByUser[e.user_id];
    if (!peers || !peers.length) return e;
    let ctx = null;
    for (const p of peers) {
      if ((p.timestamp_ms || 0) <= (e.timestamp_ms || 0)) ctx = p;else break;
    }
    if (!ctx) ctx = peers[0];
    return {
      ...e,
      entity_type: e.entity_type || ctx.entity_type,
      entity_subtype: e.entity_subtype || ctx.entity_subtype,
      model: e.model || ctx.model,
      total_tokens: e.total_tokens != null && e.total_tokens !== '' ? e.total_tokens : ctx.total_tokens,
      session_turn_index: e.session_turn_index != null && e.session_turn_index !== '' ? e.session_turn_index : ctx.session_turn_index,
      classification_signals: e.classification_signals || ctx.classification_signals,
      behavioral_alerts: e.behavioral_alerts || ctx.behavioral_alerts,
      caller_type_score: e.caller_type_score != null && e.caller_type_score !== '' ? e.caller_type_score : ctx.caller_type_score
    };
  });
}
// ─────────────── Expose for inline HTML handlers ───────────
window.switchTab = switchTab;
window.toggleDetail = toggleDetail;
window.toggleAutoRefresh = toggleAutoRefresh;
window.setIAMMode = setIAMMode;
window.recertifyAgent = recertifyAgent;
window.downloadCER = downloadCER;
window.applyFilters = applyFilters;
window.loadIAMEnrichment = loadIAMEnrichment;
window.loadRegulatoryStatus = loadRegulatoryStatus;
window.loadEvasionReport = loadEvasionReport;
window.sortBy = sortBy;
// ─────────────── Appsmith bootstrap (robust) ───────────────
function hasRealData() {
  if (typeof appsmith === 'undefined' || !appsmith.model) return false;
  const m = appsmith.model;
  const ev = m.events || m.Events || [];
  const id = m.identity || m.Identity || m.identities || [];
  return ev && ev.length > 0 || id && id.length > 0;
}
function bootDashboard() {
  try {
    renderDashboard();
  } catch (e) {
    console.error('[dashboard] boot error:', e);
  }
}
function startAppsmithBootstrap() {
  bootDashboard();
  if (typeof appsmith !== 'undefined') {
    if (typeof appsmith.onReady === 'function') {
      try {
        appsmith.onReady(function () {
          bootDashboard();
        });
      } catch (e) {}
    }
    if (typeof appsmith.onModelChange === 'function') {
      try {
        appsmith.onModelChange(function () {
          bootDashboard();
        });
      } catch (e) {}
    }
  }
  let tries = 0;
  const iv = setInterval(function () {
    tries++;
    if (hasRealData()) {
      bootDashboard();
      clearInterval(iv);
    } else if (tries > 40) {
      clearInterval(iv);
      console.warn('[dashboard] gave up waiting for data after 6s');
    }
  }, 150);
}
function wireUIOnce() {
  if (window.__dashboardWired) return;
  window.__dashboardWired = true;
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const idx = parseInt(btn.getAttribute('data-tab'), 10);
      switchTab(idx);
    });
  });
  ['f-entity', 'f-type', 'f-alert'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.addEventListener('change', applyFilters);
  });
  const search = document.getElementById('f-search');
  if (search) search.addEventListener('input', applyFilters);
  const cerPeriod = document.getElementById('cer-period');
  if (cerPeriod) cerPeriod.addEventListener('change', loadRegulatoryStatus);

  // ── FIX 1: Wire sort headers via addEventListener instead of inline onclick ──
  var sortColumns = ['_time', 'event_type', 'display_name', 'entity_type', 'model', 'latency_ms', 'total_tokens', 'session_turn_index', 'classification_signals', 'behavioral_alerts'];
  sortColumns.forEach(function (col) {
    var el = document.getElementById('sort-' + col);
    if (el) {
      el.addEventListener('click', function () {
        sortBy(col);
      });
    }
  });
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', startAppsmithBootstrap);
} else {
  startAppsmithBootstrap();
}
// ─────────────── Master render ─────────────────────────────
function renderDashboard() {
  if (typeof appsmith === 'undefined' || !appsmith.model) return;
  const model = appsmith.model;
  if (model._debug) {
    console.log('[dashboard] model debug:', model._debug);
  }
  const rawEvents = model.events || model.Events || [];
  const rawIdentities = model.identity || model.Identity || model.identities || [];
  if (!rawEvents.length && !rawIdentities.length) {
    console.warn('[dashboard] model is empty — waiting for data. Check appsmith.model._debug in console.');
    const tbody = document.getElementById('events-body');
    if (tbody) {
      tbody.innerHTML = '<tr><td colspan="10"><div class="empty">Waiting for data to load... If this persists in deployed mode, your data source (FilePicker) may not be populated. Check console for details.</div></td></tr>';
    }
    return;
  }
  allIdentities = Array.isArray(rawIdentities) ? rawIdentities : [];
  let cleanedEvents = [];
  if (Array.isArray(rawEvents)) {
    cleanedEvents = rawEvents.map(row => {
      if (row && typeof row === 'object' && !Array.isArray(row)) {
        const keys = Object.keys(row);
        if (keys.length && keys[0].trim().startsWith('{')) {
          try {
            const reassembled = keys.map(k => k + ':' + row[k]).join(',');
            return JSON.parse(reassembled);
          } catch (e) {
            return null;
          }
        }
        return row;
      }
      return null;
    }).filter(Boolean);
  }
  const idLookup = buildIdentityLookup();
  cleanedEvents.forEach(e => {
    e.entity_type = classifyEntity(e, idLookup);
    const id = idLookup[e.user_id];
    if (id) {
      if (!e.display_name) e.display_name = id.display_name;
      if (!e.email) e.email = id.email;
      if (!e.department) e.department = id.department;
      if (!e.job_title) e.job_title = id.job_title;
      if (!e.agent_role) e.agent_role = id.agent_role;
      if (!e.sailpoint_risk) e.sailpoint_risk = id.sailpoint_risk;
      const itype = (id.identity_type || '').toLowerCase();
      if (!e.agent_id && (itype === 'agent' || id._raw && id._raw.agent_type)) {
        e.agent_id = e.user_id;
      }
    }

    // ── FIX 2: Normalize latency — resolve latency_ms from all possible data fields ──
    if (e.latency_ms == null || e.latency_ms === '') {
      // Try inter_turn_latency_ms first (present in the actual data schema)
      if (e.inter_turn_latency_ms != null && e.inter_turn_latency_ms !== '' && Number(e.inter_turn_latency_ms) > 0) {
        e.latency_ms = Number(e.inter_turn_latency_ms);
      }
      // Try prompt_submission_time_ms minus timestamp_ms as a fallback for response latency
      else if (e.response_latency_ms != null && e.response_latency_ms !== '' && Number(e.response_latency_ms) > 0) {
        e.latency_ms = Number(e.response_latency_ms);
      }
      // Try duration_ms as another fallback
      else if (e.duration_ms != null && e.duration_ms !== '' && Number(e.duration_ms) > 0) {
        e.latency_ms = Number(e.duration_ms);
      }
    } else {
      e.latency_ms = Number(e.latency_ms);
    }
