// ─────────────── Tab 9: Agent topology ─────────────────────
const DRIFT_NODE_COLOR = {
  STABLE: '#3fb950',
  MONITOR: '#58a6ff',
  INVESTIGATE: '#f0883e',
  WARNING: '#d29922',
  CRITICAL: '#f85149'
};
function buildTopology(events) {
  const agents = aggregateAgents(events);
  const nodes = agents.map(a => {
    const toolAuth = Math.min(1, a.tools_called.length / 5);
    const riskAuth = {
      CRITICAL: 1,
      HIGH: 0.8,
      MEDIUM: 0.5,
      LOW: 0.2
    }[a.risk_level] || 0.3;
    const dataSens = a.classification_signals.some(s => s.includes('PII') || s.includes('CONFIDENTIAL')) ? 0.8 : 0.3;
    const authority = toolAuth * 0.3 + riskAuth * 0.5 + dataSens * 0.2;
    return {
      agent_id: a.agent_id,
      display_name: a.display_name,
      agent_role: a.agent_role,
      orchestration_role: a.orchestration_role,
      authority_score: authority,
      authority_breakdown: {
        tool_scope: toolAuth,
        data_sens: dataSens
      },
      downstream_count: 0,
      drift_score: a.drift_score,
      drift_class: a.drift_classification,
      effective_drift_class: a.drift_classification,
      authority_escalated: authority > 0.7 && a.drift_classification === 'WARNING'
    };
  });
  return {
    nodes,
    edges: [],
    summary: {},
    kill_chains: [],
    escalated_alerts: []
  };
}
function loadAgentTopology() {
  const d = buildTopology(allEvents);
  const {
