  } = d;
  const pills = document.getElementById('topo-summary-pills');
  if (pills) {
    pills.innerHTML = [['Total Agents', nodes.length, '#1f2328'], ['High Authority', nodes.filter(n => n.authority_score >= 0.7).length, '#a40e26'], ['Escalated', nodes.filter(n => n.authority_escalated).length, '#d29922'], ['Kill Chain Paths', 0, '#0969da'], ['Edges', edges.length, '#656d76']].map(function (item) {
      return '<div style="background:#f6f8fa;border:1px solid #d0d7de;border-radius:6px;padding:7px 12px;text-align:center">' + '<div style="font-size:1.2rem;font-weight:700;color:' + item[2] + '">' + item[1] + '</div>' + '<div style="font-size:.68rem;color:#656d76;text-transform:uppercase;letter-spacing:.05em">' + item[0] + '</div>' + '</div>';
