      }).join('');
    }
  }
  const kc = document.getElementById('kill-chain-list');
  if (kc) kc.innerHTML = '<div style="font-size:.82rem;color:#656d76;padding:12px;background:#f6f8fa;border:1px solid #d0d7de;border-radius:6px">Kill chain analysis requires multi-agent edge data not present in this dataset.</div>';
  const esca = document.getElementById('escalated-alerts-body');
  if (esca) esca.innerHTML = '<tr><td colspan="6" class="empty">No escalated alerts.</td></tr>';
}
function renderTopologyCanvas(nodes, edges) {
  const canvas = document.getElementById('topology-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const W = Math.max(canvas.offsetWidth || 700, 500);
  const H = 420;
  canvas.width = W;
  canvas.height = H;
  ctx.clearRect(0, 0, W, H);
  if (!nodes.length) {
    ctx.fillStyle = '#8b949e';
    ctx.font = '14px Segoe UI, system-ui, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('No agents observed yet.', W / 2, H / 2);
    return;
  }
  const cx = W / 2,
    cy = H / 2;
  const pos = {};
  nodes.forEach((n, i) => {
    const angle = 2 * Math.PI * i / nodes.length - Math.PI / 2;
    const r = Math.min(W, H) * 0.30;
    pos[n.agent_id] = {
      x: cx + r * Math.cos(angle),
      y: cy + r * Math.sin(angle),
      vx: 0,
      vy: 0
    };
  });
  for (let iter = 0; iter < 80; iter++) {
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const pi = pos[nodes[i].agent_id],
          pj = pos[nodes[j].agent_id];
        const dx = pi.x - pj.x,
          dy = pi.y - pj.y;
        const dist = Math.max(Math.sqrt(dx * dx + dy * dy), 1);
        const force = 4500 / (dist * dist);
        const fx = force * dx / dist,
          fy = force * dy / dist;
        pi.vx += fx;
        pi.vy += fy;
        pj.vx -= fx;
        pj.vy -= fy;
      }
    }
    edges.forEach(e => {
      const ps = pos[e.source],
        pt = pos[e.target];
      if (!ps || !pt) return;
      const dx = pt.x - ps.x,
        dy = pt.y - ps.y;
      const dist = Math.max(Math.sqrt(dx * dx + dy * dy), 1);
      const ideal = 140 + (e.confidence || 0.5) * 60;
      const spring = (dist - ideal) * 0.04;
      ps.vx += spring * dx / dist;
      ps.vy += spring * dy / dist;
      pt.vx -= spring * dx / dist;
      pt.vy -= spring * dy / dist;
    });
    nodes.forEach(n => {
      const p = pos[n.agent_id];
      p.vx += (cx - p.x) * 0.012;
      p.vy += (cy - p.y) * 0.012;
      p.vx *= 0.78;
      p.vy *= 0.78;
      p.x = Math.max(45, Math.min(W - 45, p.x + p.vx));
      p.y = Math.max(45, Math.min(H - 45, p.y + p.vy));
    });
  }
  edges.forEach(e => {
    const ps = pos[e.source],
      pt = pos[e.target];
    if (!ps || !pt) return;
    ctx.strokeStyle = 'rgba(139,148,158,0.5)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(ps.x, ps.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.stroke();
  });
  nodes.forEach(n => {
    const p = pos[n.agent_id];
    const nr = 14 + (n.authority_score || 0) * 22;
    const dc = n.effective_drift_class || n.drift_class || 'STABLE';
    const fillColor = DRIFT_NODE_COLOR[dc] || '#8b949e';
    if (n.authority_escalated) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, nr + 5, 0, 2 * Math.PI);
      ctx.strokeStyle = '#f85149';
      ctx.lineWidth = 2.5;
      ctx.setLineDash([4, 3]);
      ctx.stroke();
      ctx.setLineDash([]);
    }
    ctx.beginPath();
    ctx.arc(p.x, p.y, nr, 0, 2 * Math.PI);
    ctx.fillStyle = fillColor;
    ctx.fill();
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 2;
    ctx.stroke();
    ctx.fillStyle = '#fff';
    ctx.font = 'bold ' + Math.max(9, Math.round(nr * 0.38)) + 'px Segoe UI, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    const label = (n.display_name || n.agent_id).substring(0, 11);
    ctx.fillText(label, p.x, p.y - 4);
    ctx.font = Math.max(8, Math.round(nr * 0.3)) + 'px Segoe UI, sans-serif';
    ctx.fillStyle = 'rgba(255,255,255,0.85)';
    ctx.fillText(Math.round((n.authority_score || 0) * 100) + '%', p.x, p.y + 7);
  });
}
// ─────────────── Tab 10: Regulatory ────────────────────────
function loadRegulatoryStatus() {
  const agents = aggregateAgents(allEvents);
  const frameworks = ['EU AI Act', 'SR 11-7', 'NIST AI RMF', 'FFIEC', 'ISO 42001'];
  const evaluate = a => {
    if (a.behavioral_alerts.some(x => CRIT_ALERTS.has(x))) return 'GAP';
    if (a.call_count >= 100 && a.zasp_scores.length > 0) return 'SATISFIED';
    if (a.zasp_scores.length > 0) return 'PARTIAL';
    return 'GAP';
  };
  const agentRows = agents.map(a => {
    const status = evaluate(a);
    const byFw = {};
    frameworks.forEach(fw => byFw[fw] = status);
    return {
      agent_id: a.agent_id,
      display_name: a.display_name,
      agent_role: a.agent_role,
      call_count: a.call_count,
      overall_status: status,
      coverage_pct: status === 'SATISFIED' ? 100 : status === 'PARTIAL' ? 50 : 0,
      by_framework: byFw
    };
  });
  const satisfied = agentRows.filter(a => a.overall_status === 'SATISFIED').length;
  const overallCov = agentRows.length ? Math.round(satisfied / agentRows.length * 100) : 0;
  const gaps = {};
  frameworks.forEach(fw => {
    const gap = agentRows.some(a => a.by_framework[fw] === 'GAP');
    if (gap) gaps[fw] = true;
  });
  const summary = document.getElementById('reg-summary');
  if (summary) summary.innerHTML = '<div class="card"><h3>Total Agents</h3><div class="big-num">' + agentRows.length + '</div></div>' + '<div class="card"><h3>Fully Satisfied</h3><div class="big-num" style="color:#1a7f37">' + satisfied + '</div><div class="sub">' + overallCov + '% coverage</div></div>' + '<div class="card"><h3>Framework Gaps</h3><div class="big-num" style="color:#a40e26">' + Object.keys(gaps).length + '</div><div class="sub">' + (Object.keys(gaps).join(', ') || 'None') + '</div></div>';
  const fwEl = document.getElementById('fw-status-row');
  if (fwEl) {
    fwEl.innerHTML = frameworks.map(fw => {
      const gapCount = agentRows.filter(a => a.by_framework[fw] === 'GAP').length;
      const worst = gapCount > 0 ? 'GAP' : agentRows.some(a => a.by_framework[fw] === 'PARTIAL') ? 'PARTIAL' : 'SATISFIED';
