  }
  const bars = document.getElementById('evasion-signal-bars');
  if (bars) {
    const SIGNAL_LABELS = {
      LATENCY_MIMICRY: 'Latency Mimicry',
      TEMPLATE_VARIATION: 'Template Variation'
    };
    const SIGNAL_COLORS = {
      LATENCY_MIMICRY: '#d29922',
      TEMPLATE_VARIATION: '#f0883e'
    };
    if (!Object.keys(signalCounts).length) {
      bars.innerHTML = '<span style="font-size:.8rem;color:#8b949e">No evasion signals detected.</span>';
    } else {
      const maxVal = Math.max(...Object.values(signalCounts));
      bars.innerHTML = Object.entries(signalCounts).sort((a, b) => b[1] - a[1]).map(function (entry) {
        var type = entry[0],
          cnt = entry[1];
        var label = SIGNAL_LABELS[type] || type;
        var color = SIGNAL_COLORS[type] || '#58a6ff';
        var p = maxVal > 0 ? (cnt / maxVal * 100).toFixed(1) : 0;
        return '<div style="min-width:220px;flex:1">' + '<div style="display:flex;justify-content:space-between;margin-bottom:4px">' + '<span style="font-size:.78rem;font-weight:500;color:#1f2328">' + esc(label) + '</span>' + '<span style="font-size:.78rem;color:#656d76">' + cnt + '</span>' + '</div>' + '<div style="height:8px;background:#eaeef2;border-radius:4px;overflow:hidden">' + '<div style="height:100%;width:' + p + '%;background:' + color + ';border-radius:4px"></div>' + '</div>' + '</div>';
      }).join('');
    }
  }
  const tbody = document.getElementById('evasion-tbody');
  if (tbody) {
    if (!highConf.length) {
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#8b949e;padding:16px">No high-confidence evasion events detected.</td></tr>';
    } else {
      tbody.innerHTML = highConf.map(ev => '<tr>' + '<td><code style="font-size:.72rem">' + esc(ev.session_id.slice(0, 20)) + '...</code></td>' + '<td><span style="background:#d2992222;color:#d29922;border:1px solid #d2992244;border-radius:4px;padding:2px 8px;font-size:.72rem;font-weight:600">' + esc(ev.signal_type) + '</span></td>' + '<td><span style="color:#d29922;font-weight:600">' + (ev.confidence * 100).toFixed(0) + '%</span></td>' + '<td><span style="background:#fff5f5;color:#cf222e;border:1px solid #ffb3b3;border-radius:4px;padding:2px 8px;font-size:.7rem">INCONSISTENT_SIGNALS</span></td>' + '<td><span style="background:#fff8e1;color:#d29922;border:1px solid #ffe066;border-radius:4px;padding:2px 8px;font-size:.7rem">REQUIRED</span></td>' + '<td style="font-size:.75rem;color:#656d76">' + esc(ev.detected_at_iso || '—') + '</td>' + '</tr>').join('');
    }
  }
  const lim = document.getElementById('evasion-limitations');
  if (lim) lim.innerHTML = '<p style="font-size:.8rem;color:#8b949e">Limitations metadata not available in the current dataset.</p>';
  const gov = document.getElementById('evasion-governance');
  if (gov) gov.innerHTML = '<p style="font-size:.8rem;color:#8b949e">Governance metadata not available in the current dataset.</p>';
  const agg = document.getElementById('agg-policy-tbody');
  if (agg) agg.innerHTML = '<tr><td colspan="3" style="text-align:center;color:#8b949e;padding:12px">No policy data in the current dataset.</td></tr>';
}
// ─────────────── Helpers ───────────────────────────────────
function esc(s) {
  if (s == null) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
