function pct(v) {
  return v != null ? (v * 100).toFixed(1) + '%' : '—';
}
function riskBadge(r) {
  const m = {
    CRITICAL: 'critical',
    HIGH: 'warning',
    MEDIUM: 'investigate',
    LOW: 'monitor',
    'LOW-MED': 'monitor'
  };
  return m[r] || 'unknown';
}
function orchBadge(r) {
  const m = {
    ORCHESTRATOR: 'llm',
    SUBAGENT: 'ok',
    STANDALONE: 'agent'
  };
  return m[r] || 'unknown';
}
function rebuildChart(id, type, data, options) {
  const canvas = document.getElementById(id);
  if (!canvas) return;
  if (charts[id]) charts[id].destroy();
  charts[id] = new Chart(canvas, {
    type,
    data,
    options: {
      responsive: true,
      maintainAspectRatio: true,
      ...options
    }
  });
}

