    const agentKey = e.agent_id || (!isHuman ? e.user_id : null) || e.app_id;
    if (!agentKey) return;
    const idRow = idLookup[agentKey] || idLookup[e.user_id] || {};
    const a = byAgent[agentKey] = byAgent[agentKey] || {
      agent_id: agentKey,
      display_name: idRow.display_name || idRow.name || e.display_name || agentKey.slice(0, 24),
      agent_type: inferAgentType(e),
      agent_role: idRow.agent_role || idRow.role || e.agent_role || e.job_title || null,
