    if (e.drift_classification) a.drift_classifications.push(e.drift_classification);
    if (e.tool_name) a.tools_called.add(e.tool_name);
    if (e.tools_called) {
      String(e.tools_called).split('|').filter(Boolean).forEach(t => a.tools_called.add(t));
    }
    if (e.classification_signals) {
      String(e.classification_signals).split('|').filter(Boolean).forEach(s => a.classification_signals.add(s));
    }
    if (e.behavioral_alerts) {
      String(e.behavioral_alerts).split('|').filter(Boolean).forEach(s => a.behavioral_alerts.add(s));
    }
    if (e.timestamp_iso) {
      if (e.timestamp_iso < a.first_seen_iso) a.first_seen_iso = e.timestamp_iso;
      if (e.timestamp_iso > a.last_seen_iso) {
