  allEvents.forEach(e => {
    if (e.entity_type === 'HUMAN') {
      const k = e.job_title || e.department || 'Unknown';
      if (!humanByRole[k]) humanByRole[k] = { role: k, count: 0, conf_sum: 0, conf_n: 0 };
      humanByRole[k].count++;
      if (e.caller_type_score != null && e.caller_type_score !== '') {
        humanByRole[k].conf_sum += Number(e.caller_type_score);
        humanByRole[k].conf_n++;
      }
