      agentByRole[e.agent_role].count++;
      if (e.caller_type_score != null && e.caller_type_score !== '') {
        agentByRole[e.agent_role].conf_sum += Number(e.caller_type_score);
        agentByRole[e.agent_role].conf_n++;
