// ─────────────── Tab 5: Tool scope ─────────────────────────
function loadToolScope() {
  const tbody = document.getElementById('tool-body');
  if (!tbody) return;
  const BASELINE_CALLS = 50;
  const byAgent = {};
  const sorted = [...allEvents].sort((a, b) => (a.timestamp_ms || 0) - (b.timestamp_ms || 0));
  sorted.forEach(e => {
    const key = e.agent_id || e.app_id;
    if (!key) return;
    if (!byAgent[key]) {
      byAgent[key] = {
        agent_id: key,
        call_index: 0,
        baseline_tools: new Set(),
        post_tools: new Set(),
        all_tools: new Set(),
      };
    }
    const rec = byAgent[key];
    rec.call_index++;
    if (e.tool_name) {
      rec.all_tools.add(e.tool_name);
      if (rec.call_index <= BASELINE_CALLS) {
        rec.baseline_tools.add(e.tool_name);
      } else {
        rec.post_tools.add(e.tool_name);
      }
    }
  });
  const agents = aggregateAgents(allEvents);
  const meta = Object.fromEntries(agents.map(a => [a.agent_id, a]));
