    return;
  }
  tbody.innerHTML = rows.map(r => {
    const m = meta[r.agent_id] || {};
    const newTools = [...r.post_tools].filter(t => !r.baseline_tools.has(t));
    const hasGap = newTools.length > 0;
    const observed = [...r.all_tools];
    return '<tr>' +
      '<td><code style="font-size:.73rem">' + esc(r.agent_id) + '</code></td>' +
      '<td>' + esc(m.agent_role || '—') + '</td>' +
