// ─────────────── Tab 11: Evasion detection ─────────────────
function loadEvasionReport() {
  const sessions = {};
  allEvents.forEach(e => {
    const sid = e.span_id || e.event_id;
    if (!sid) return;
    sessions[sid] = sessions[sid] || { session_id: sid, signals: new Set(), alerts: new Set(), ts: e.timestamp_iso };
    (e.classification_signals || '').split('|').filter(Boolean).forEach(s => sessions[sid].signals.add(s));
    (e.behavioral_alerts || '').split('|').filter(Boolean).forEach(a => sessions[sid].alerts.add(a));
  });
  const sessionArr = Object.values(sessions);
  const signalCounts = {};
  sessionArr.forEach(s => {
    if ([...s.signals].some(x => x.includes('LATENCY'))) signalCounts.LATENCY_MIMICRY = (signalCounts.LATENCY_MIMICRY || 0) + 1;
    if ([...s.signals].some(x => x.includes('TEMPLATE'))) signalCounts.TEMPLATE_VARIATION = (signalCounts.TEMPLATE_VARIATION || 0) + 1;
  });
  const flagged = sessionArr.filter(s => {
    const sigs = [...s.signals];
    return sigs.some(x => x.includes('HUMAN_LATENCY')) && sigs.some(x => x.includes('TEMPLATE'));
  });
  const highConf = flagged.map(s => ({
    session_id: s.session_id,
    signal_type: 'LATENCY_MIMICRY',
    confidence: 0.75,
    inconsistent_signals_flag: true,
    requires_manual_review: true,
    detected_at_iso: s.ts,
  }));
  const summary = document.getElementById('evasion-summary');
  if (summary) {
    const flagRate = sessionArr.length ? ((flagged.length / sessionArr.length) * 100).toFixed(1) : '0.0';
    const totalSignals = Object.values(signalCounts).reduce((a, b) => a + b, 0);
    summary.innerHTML =
      '<div class="card"><div class="big-num">' + sessionArr.length + '</div><div class="sub">Sessions Analyzed</div></div>' +
      '<div class="card"' + (flagged.length > 0 ? ' style="border-color:#f85149"' : '') + '><div class="big-num"' + (flagged.length > 0 ? ' style="color:#cf222e"' : '') + '>' + flagged.length + '</div><div class="sub">Flagged (INCONSISTENT_SIGNALS)</div></div>' +
      '<div class="card"><div class="big-num">' + flagRate + '%</div><div class="sub">Flag Rate</div></div>' +
      '<div class="card"><div class="big-num">' + totalSignals + '</div><div class="sub">Total Evasion Signals</div></div>' +
      '<div class="card"><div class="big-num">' + highConf.length + '</div><div class="sub">High-Confidence Events</div></div>';
  }
  const bars = document.getElementById('evasion-signal-bars');
  if (bars) {
    const SIGNAL_LABELS = { LATENCY_MIMICRY: 'Latency Mimicry', TEMPLATE_VARIATION: 'Template Variation' };
    const SIGNAL_COLORS = { LATENCY_MIMICRY: '#d29922', TEMPLATE_VARIATION: '#f0883e' };
    if (!Object.keys(signalCounts).length) {
      bars.innerHTML = '<span style="font-size:.8rem;color:#8b949e">No evasion signals detected.</span>';
    } else {
      const maxVal = Math.max(...Object.values(signalCounts));
      bars.innerHTML = Object.entries(signalCounts).sort((a, b) => b[1] - a[1]).map(function(entry) {
        var type = entry[0], cnt = entry[1];
        var label = SIGNAL_LABELS[type] || type;
        var color = SIGNAL_COLORS[type] || '#58a6ff';
        var p = maxVal > 0 ? (cnt / maxVal * 100).toFixed(1) : 0;
        return '<div style="min-width:220px;flex:1">' +
          '<div style="display:flex;justify-content:space-between;margin-bottom:4px">' +
            '<span style="font-size:.78rem;font-weight:500;color:#1f2328">' + esc(label) + '</span>' +
            '<span style="font-size:.78rem;color:#656d76">' + cnt + '</span>' +
          '</div>' +
          '<div style="height:8px;background:#eaeef2;border-radius:4px;overflow:hidden">' +
            '<div style="height:100%;width:' + p + '%;background:' + color + ';border-radius:4px"></div>' +
          '</div>' +
        '</div>';
      }).join('');
    }
  }
  const tbody = document.getElementById('evasion-tbody');
  if (tbody) {
    if (!highConf.length) {
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#8b949e;padding:16px">No high-confidence evasion events detected.</td></tr>';
    } else {
      tbody.innerHTML = highConf.map(ev =>
        '<tr>' +
        '<td><code style="font-size:.72rem">' + esc(ev.session_id.slice(0, 20)) + '...</code></td>' +
        '<td><span style="background:#d2992222;color:#d29922;border:1px solid #d2992244;border-radius:4px;padding:2px 8px;font-size:.72rem;font-weight:600">' + esc(ev.signal_type) + '</span></td>' +
        '<td><span style="color:#d29922;font-weight:600">' + (ev.confidence * 100).toFixed(0) + '%</span></td>' +
        '<td><span style="background:#fff5f5;color:#cf222e;border:1px solid #ffb3b3;border-radius:4px;padding:2px 8px;font-size:.7rem">INCONSISTENT_SIGNALS</span></td>' +
        '<td><span style="background:#fff8e1;color:#d29922;border:1px solid #ffe066;border-radius:4px;padding:2px 8px;font-size:.7rem">REQUIRED</span></td>' +
        '<td style="font-size:.75rem;color:#656d76">' + esc(ev.detected_at_iso || '—') + '</td>' +
        '</tr>'
      ).join('');
    }
  }
  const lim = document.getElementById('evasion-limitations');
  if (lim) lim.innerHTML = '<p style="font-size:.8rem;color:#8b949e">Limitations metadata not available in the current dataset.</p>';
  const gov = document.getElementById('evasion-governance');
  if (gov) gov.innerHTML = '<p style="font-size:.8rem;color:#8b949e">Governance metadata not available in the current dataset.</p>';
  const agg = document.getElementById('agg-policy-tbody');
  if (agg) agg.innerHTML = '<tr><td colspan="3" style="text-align:center;color:#8b949e;padding:12px">No policy data in the current dataset.</td></tr>';
}
// ─────────────── Helpers ───────────────────────────────────
function esc(s) {
  if (s == null) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function pct(v) { return v != null ? (v * 100).toFixed(1) + '%' : '—'; }
function riskBadge(r) {
  const m = { CRITICAL: 'critical', HIGH: 'warning', MEDIUM: 'investigate', LOW: 'monitor', 'LOW-MED': 'monitor' };
  return m[r] || 'unknown';
}
function orchBadge(r) {
  const m = { ORCHESTRATOR: 'llm', SUBAGENT: 'ok', STANDALONE: 'agent' };
  return m[r] || 'unknown';
}
function rebuildChart(id, type, data, options) {
  const canvas = document.getElementById(id);
  if (!canvas) return;
  if (charts[id]) charts[id].destroy();
  charts[id] = new Chart(canvas, { type, data, options: { responsive: true, maintainAspectRatio: true, ...options } });
}
